+            .iter()
+            .filter(|(_, stored_reason)| stored_reason.as_str() == reason)
+            .map(|(key, stored_reason)| MemoQuarantineInspectionItem {
+                key: key.clone(),
+                reason: stored_reason.clone(),
+            })
+            .collect();
+        sort_quarantine_inspection_items(&mut items);
+        items
+    }
